import UIKit
import WebKit

final class WebViewController: UIViewController, WKNavigationDelegate {
    private var webView: WKWebView!

    override func loadView() {
        let configuration = WKWebViewConfiguration()
        configuration.preferences.javaScriptCanOpenWindowsAutomatically = true
        webView = WKWebView(frame: .zero, configuration: configuration)
        webView.navigationDelegate = self
        view = webView
    }

    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .systemBackground
        webView.loadHTMLString(Self.embeddedHtml, baseURL: nil)
    }

    private static let embeddedHtml = #"""
<!doctype html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover">
<title>信用卡档案</title>
<style>
:root{color-scheme:light;--bg:#f7faf8;--text:#14211f;--muted:#6b7b78;--line:#dce8e4;--brand:#0f766e;--soft:#eaf5f1;font-family:-apple-system,BlinkMacSystemFont,"PingFang SC",sans-serif}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text)}button,input,select,textarea{font:inherit}button{border:1px solid var(--line);background:white;border-radius:8px;padding:10px 12px;font-weight:700}.app{padding:max(14px,env(safe-area-inset-top)) 14px max(24px,env(safe-area-inset-bottom));max-width:760px;margin:0 auto}.topbar{display:flex;align-items:center;justify-content:space-between;gap:12px}h1{margin:0;font-size:30px}p{margin:4px 0 0;color:var(--muted)}.primary{background:var(--brand);color:white;border-color:var(--brand)}.tabs{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin:18px 0}.tab.active{background:var(--soft);color:var(--brand);border-color:#badbd5}.panel{display:none}.panel.active{display:block}.toolbar{display:grid;gap:8px;margin-bottom:12px}input,select,textarea{width:100%;border:1px solid var(--line);border-radius:8px;padding:11px 12px;background:white;color:var(--text)}textarea{min-height:110px;resize:vertical}.list{display:grid;gap:10px}.card{background:white;border:1px solid var(--line);border-radius:10px;padding:14px;box-shadow:0 8px 24px rgba(20,33,31,.06)}.card h2,.card h3{margin:0 0 4px;font-size:20px}.meta{color:var(--muted);line-height:1.55}.chips{display:flex;flex-wrap:wrap;gap:6px;margin-top:10px}.chip{background:var(--soft);color:#244b46;border-radius:999px;padding:5px 9px;font-weight:700;font-size:13px}.actions{display:flex;gap:8px;margin-top:12px;flex-wrap:wrap}.danger{color:#b42318}.data-actions{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:10px}#dataBox{min-height:56vh;font-family:ui-monospace,Menlo,monospace;font-size:12px}dialog{width:min(94vw,620px);border:0;border-radius:12px;padding:0}dialog::backdrop{background:rgba(0,0,0,.35)}form{padding:14px;display:grid;gap:10px}.dialog-head,.dialog-actions{display:flex;align-items:center;justify-content:space-between;gap:10px}label{display:grid;gap:5px;color:var(--muted);font-weight:700}label input,label textarea{color:var(--text);font-weight:400}
</style>
</head>
<body>
<main class="app">
<header class="topbar"><div><h1>信用卡档案</h1><p>iOS 内嵌测试版 0.1.2 build 3</p></div><button id="addCardBtn" class="primary" type="button">新增</button></header>
<nav class="tabs"><button class="tab active" data-view="cards" type="button">档案</button><button class="tab" data-view="reminders" type="button">提醒</button><button class="tab" data-view="usage" type="button">用卡</button><button class="tab" data-view="data" type="button">数据</button></nav>
<section class="panel active" id="cardsView"><div class="toolbar"><input id="searchInput" type="search" placeholder="搜索银行、卡名、尾号"><select id="sortMode"><option value="best">智能排序</option><option value="statement">按账单日</option><option value="payment">按还款日</option><option value="cashback">只看返利卡</option></select></div><div id="cardList" class="list"></div></section>
<section class="panel" id="remindersView"><div id="reminderList" class="list"></div></section>
<section class="panel" id="usageView"><div id="usageList" class="list"></div></section>
<section class="panel" id="dataView"><div class="data-actions"><button id="copyBtn" class="primary" type="button">复制 JSON</button><button id="pasteBtn" type="button">粘贴导入</button><button id="resetBtn" type="button">清空</button></div><textarea id="dataBox" spellcheck="false"></textarea></section>
</main>
<dialog id="cardDialog"><form id="cardForm" method="dialog"><div class="dialog-head"><h2>卡片档案</h2><button id="closeDialogBtn" type="button">×</button></div><input id="cardId" type="hidden"><label>银行<input id="bank" required placeholder="例如 中信银行"></label><label>卡名<input id="cardName" required placeholder="例如 VISA Signature"></label><label>尾号<input id="last4" maxlength="4" inputmode="numeric"></label><label>账单日<input id="statementDay" type="number" min="1" max="31"></label><label>还款日<input id="paymentDay" type="number" min="1" max="31"></label><label>年费日<input id="annualFeeDate" type="date"></label><label>提醒提前天数<input id="reminderLeadDays" type="number" min="0" max="30" placeholder="默认2天"></label><label>提醒时间<input id="reminderTime" type="time" value="10:00"></label><label>返利类型<input id="cashbackType" placeholder="例如 现金返现 / 账单抵扣"></label><label>返利比例<input id="cashbackRate" placeholder="例如 1.5% / 满300返30"></label><label>适合用途<input id="useTags" placeholder="大额, 境外, 酒店"></label><label>新旧卡关联<textarea id="replacement" placeholder="只做档案线索，不进入提醒"></textarea></label><label>备注<textarea id="notes"></textarea></label><div class="dialog-actions"><button id="cancelBtn" type="button">取消</button><button class="primary" type="submit">保存</button></div></form></dialog>
<script>
const STORAGE_KEY='credit-card-archive-ios-inline-v1';const DEFAULT_LEAD_DAYS=2,DEFAULT_TIME='10:00';let state=loadState();const $=s=>document.querySelector(s);const els={tabs:document.querySelectorAll('.tab'),panels:document.querySelectorAll('.panel'),addCardBtn:$('#addCardBtn'),cardDialog:$('#cardDialog'),cardForm:$('#cardForm'),closeDialogBtn:$('#closeDialogBtn'),cancelBtn:$('#cancelBtn'),searchInput:$('#searchInput'),sortMode:$('#sortMode'),cardList:$('#cardList'),reminderList:$('#reminderList'),usageList:$('#usageList'),dataBox:$('#dataBox'),copyBtn:$('#copyBtn'),pasteBtn:$('#pasteBtn'),resetBtn:$('#resetBtn')};const fields=['cardId','bank','cardName','last4','statementDay','paymentDay','annualFeeDate','reminderLeadDays','reminderTime','cashbackType','cashbackRate','useTags','replacement','notes'].reduce((m,id)=>({...m,[id]:$('#'+id)}),{});function loadState(){try{return JSON.parse(localStorage.getItem(STORAGE_KEY))||{cards:[]}}catch{return{cards:[]}}}function saveState(){localStorage.setItem(STORAGE_KEY,JSON.stringify(state,null,2))}function makeId(){return Date.now()+'-'+Math.random().toString(16).slice(2)}function esc(v){return String(v??'').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;')}function today(){const d=new Date();d.setHours(0,0,0,0);return d}function daysInMonth(y,m){return new Date(y,m+1,0).getDate()}function nextMonthlyDate(day){if(!day)return null;const now=today();let d=new Date(now.getFullYear(),now.getMonth(),Math.min(Number(day),daysInMonth(now.getFullYear(),now.getMonth())));if(d<now)d=new Date(now.getFullYear(),now.getMonth()+1,Math.min(Number(day),daysInMonth(now.getFullYear(),now.getMonth()+1)));return d}function parseDate(v){if(!v)return null;const d=new Date(v+'T00:00:00');return Number.isNaN(d.getTime())?null:d}function annualDate(v){const b=parseDate(v);if(!b)return null;const n=today();let d=new Date(n.getFullYear(),b.getMonth(),b.getDate());if(d<n)d=new Date(n.getFullYear()+1,b.getMonth(),b.getDate());return d}function daysUntil(d){return d?Math.round((d-today())/86400000):Infinity}function addDays(d,n){const x=new Date(d);x.setDate(x.getDate()+n);return x}function leadDays(v){const n=Number(v);return Number.isFinite(n)&&n>=0?Math.min(n,30):DEFAULT_LEAD_DAYS}function reminderTime(d,c){if(!d)return null;const x=addDays(d,-leadDays(c.reminderLeadDays));const [h=10,m=0]=String(c.reminderTime||DEFAULT_TIME).split(':').map(Number);x.setHours(h,m,0,0);return x}function fmt(d){return d?`${d.getMonth()+1}月${d.getDate()}日`:'未设置'}function fmtTime(d){return d?`${fmt(d)} ${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`:'不提醒'}function hasCashback(c){return /返利|返现|cashback|账单抵扣|现金|满减|立减/.test([c.cashbackType,c.cashbackRate].join(' ').toLowerCase())}function getCards(){const kw=els.searchInput.value.trim().toLowerCase();let cards=state.cards.filter(c=>!kw||[c.bank,c.name,c.last4,c.useTags,c.cashbackType].join(' ').toLowerCase().includes(kw));if(els.sortMode.value==='cashback')cards=cards.filter(hasCashback);return cards.sort((a,b)=>{if(els.sortMode.value==='statement')return daysUntil(nextMonthlyDate(a.statementDay))-daysUntil(nextMonthlyDate(b.statementDay));if(els.sortMode.value==='payment')return daysUntil(nextMonthlyDate(a.paymentDay))-daysUntil(nextMonthlyDate(b.paymentDay));return daysUntil(nextMonthlyDate(b.paymentDay))-daysUntil(nextMonthlyDate(a.paymentDay))})}function getReminders(){const rs=[];state.cards.forEach(c=>{const name=`${c.bank||''} ${c.name||''} 尾号${c.last4||'未填'}`.trim();[['账单',nextMonthlyDate(c.statementDay),'账单日后适合拉长还款周期'],['还款',nextMonthlyDate(c.paymentDay),'确认是否已还款，避免逾期'],['年费',annualDate(c.annualFeeDate),'检查年费规则']].forEach(([type,date,meta])=>{if(date)rs.push({type,date,title:`${name} ${type}日`,meta,remindAt:reminderTime(date,c)})})});return rs.sort((a,b)=>a.date-b.date||a.remindAt-b.remindAt)}function renderCards(){const cards=getCards();els.cardList.innerHTML=cards.length?cards.map(c=>`<article class="card"><h2>${esc(c.bank||'未填写银行')}</h2><div class="meta">${esc(c.name||'未命名卡片')} · 尾号 ${esc(c.last4||'未填')}</div><div class="chips"><span class="chip">账单 ${esc(c.statementDay||'未设')}</span><span class="chip">还款 ${esc(c.paymentDay||'未设')}</span>${hasCashback(c)?'<span class="chip">返利</span>':''}</div><p class="meta">${esc(c.notes||c.replacement||'暂无备注')}</p><div class="actions"><button data-action="edit" data-id="${c.id}" type="button">编辑</button><button class="danger" data-action="delete" data-id="${c.id}" type="button">删除</button></div></article>`).join(''):`<article class="card"><h3>暂无卡片</h3><p>先新增一张卡。</p></article>`}function renderReminders(){const rs=getReminders();els.reminderList.innerHTML=rs.length?rs.map(r=>{const due=daysUntil(r.date);return `<article class="card"><h3>${esc(r.title)}</h3><div class="meta">${fmt(r.date)} · ${due===0?'今天':due>0?`${due}天后`:`已过${Math.abs(due)}天`}</div><p class="meta">${esc(r.meta)} · 提醒 ${fmtTime(r.remindAt)}</p></article>`}).join(''):`<article class="card"><h3>暂无提醒</h3></article>`}function renderUsage(){const cb=state.cards.filter(hasCashback);const best=[...state.cards].sort((a,b)=>daysUntil(nextMonthlyDate(b.paymentDay))-daysUntil(nextMonthlyDate(a.paymentDay))).slice(0,3);els.usageList.innerHTML=`<article class="card"><h3>返利</h3>${cb.length?cb.map(c=>`<p class="meta">${esc(c.bank)} ${esc(c.name)} · ${esc(c.cashbackType||c.cashbackRate)}</p>`).join(''):'<p class="meta">没有设置返利字段的卡</p>'}</article><article class="card"><h3>最长还款</h3>${best.map(c=>`<p class="meta">${esc(c.bank)} ${esc(c.name)} · 还款日 ${esc(c.paymentDay||'未设')}</p>`).join('')}</article>`}function renderData(){els.dataBox.value=JSON.stringify(state,null,2)}function render(){renderCards();renderReminders();renderUsage();renderData();saveState()}function openCard(c=null){fields.cardId.value=c?.id||'';fields.bank.value=c?.bank||'';fields.cardName.value=c?.name||'';fields.last4.value=c?.last4||'';fields.statementDay.value=c?.statementDay||'';fields.paymentDay.value=c?.paymentDay||'';fields.annualFeeDate.value=c?.annualFeeDate||'';fields.reminderLeadDays.value=c?.reminderLeadDays??'';fields.reminderTime.value=c?.reminderTime||DEFAULT_TIME;fields.cashbackType.value=c?.cashbackType||'';fields.cashbackRate.value=c?.cashbackRate||'';fields.useTags.value=c?.useTags||'';fields.replacement.value=c?.replacement||'';fields.notes.value=c?.notes||'';els.cardDialog.showModal()}function saveCard(){const c={id:fields.cardId.value||makeId(),bank:fields.bank.value.trim(),name:fields.cardName.value.trim(),last4:fields.last4.value.trim().slice(-4),statementDay:fields.statementDay.value,paymentDay:fields.paymentDay.value,annualFeeDate:fields.annualFeeDate.value,reminderLeadDays:fields.reminderLeadDays.value===''?'':Number(fields.reminderLeadDays.value),reminderTime:fields.reminderTime.value||DEFAULT_TIME,cashbackType:fields.cashbackType.value.trim(),cashbackRate:fields.cashbackRate.value.trim(),useTags:fields.useTags.value.trim(),replacement:fields.replacement.value.trim(),notes:fields.notes.value.trim()};const i=state.cards.findIndex(x=>x.id===c.id);if(i>=0)state.cards[i]=c;else state.cards.unshift(c);render()}function setView(v){els.panels.forEach(p=>p.classList.toggle('active',p.id===v+'View'));els.tabs.forEach(t=>t.classList.toggle('active',t.dataset.view===v));if(v==='cards'){els.searchInput.value='';els.sortMode.value='best';renderCards()}}els.tabs.forEach(t=>t.addEventListener('click',()=>setView(t.dataset.view)));els.addCardBtn.addEventListener('click',()=>openCard());els.closeDialogBtn.addEventListener('click',()=>els.cardDialog.close());els.cancelBtn.addEventListener('click',()=>els.cardDialog.close());els.cardForm.addEventListener('submit',e=>{e.preventDefault();saveCard();els.cardDialog.close()});els.searchInput.addEventListener('input',renderCards);els.sortMode.addEventListener('change',renderCards);document.addEventListener('click',e=>{const b=e.target.closest('[data-action]');if(!b)return;const c=state.cards.find(x=>x.id===b.dataset.id);if(b.dataset.action==='edit'&&c)openCard(c);if(b.dataset.action==='delete'){state.cards=state.cards.filter(x=>x.id!==b.dataset.id);render()}});els.copyBtn.addEventListener('click',async()=>{renderData();els.dataBox.select();try{await navigator.clipboard.writeText(els.dataBox.value)}catch{document.execCommand('copy')}});els.pasteBtn.addEventListener('click',()=>{const txt=prompt('粘贴 JSON');if(!txt)return;try{state=JSON.parse(txt);render()}catch{alert('JSON 格式不正确')}});els.resetBtn.addEventListener('click',()=>{if(confirm('确定清空？')){state={cards:[]};render()}});render();
</script>
</body>
</html>
"""
}
